mapper.select:
SELECT id, fqc_daily_input AS fqcDailyInput, fqc_daily_output AS fqcDailyOutput, fqc_quantity_instock AS fqcQuantityInstock, fqc_withstand_undistributed AS fqcWithstandUndistributed, fqc_function_undistributed AS fqcFunctionUndistributed, (fqc_daily_input - IFNULL(fqc_withstand_undistributed, 0)) AS fqcAllocated, (fqc_daily_output + IFNULL(fqc_function_undistributed, 0)) AS fqcFunctionalTestOutput, DATE(create_time) AS createTime, DATE(update_time) AS updateTime FROM fqc_display
(is_deleted = 0 OR is_deleted IS NULL)
AND ( fqc_daily_input LIKE CONCAT('%', #{queryParams.keywords}, '%') OR fqc_daily_output LIKE CONCAT('%', #{queryParams.keywords}, '%') OR fqc_quantity_instock LIKE CONCAT('%', #{queryParams.keywords}, '%') OR fqc_withstand_undistribited LIKE CONCAT('%', #{queryParams.keywords}, '%') OR fqc_function_undistribited LIKE CONCAT('%', #{queryParams.keywords}, '%') )
AND DATE(create_time) >= #{queryParams.createTimeStart}
AND DATE(create_time) <= #{queryParams.createTimeEnd}
AND DATE(update_time) >= #{queryParams.updateTimeStart}
AND DATE(update_time) <= #{queryParams.updateTimeEnd}
ORDER BY create_time DESC
